// src/App.js
import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Welcome from './welcome';
import Login from './Login';

const App = () => {
  return (
    <Router>
      <Routes>
        <Route path="/" component={Welcome} />
        <Route path="/login" component={Login} />
      </Routes>
    </Router>
  );
};

export default App;
